      if (spec === "o") { let o = U().toString(8); if (prec !== undefined) o = o.padStart(prec, "0"); return pad(o, flags, width); }
      const f = F();
      if (spec === "f" || spec === "F") return pad(sign(f < 0, flags) + Math.abs(f).toFixed(prec === undefined ? 6 : prec), flags, width);
